pub const LLM_EXECUTOR_GAS_PRICE_WEI: u128 = 1_000_000_000;
pub const LLM_ALPHA: f64 = 0.25;
pub const LLM_BETA: f64 = 2.5;
pub const LLM_GAMMA: f64 = 0.75;
pub const LLM_DELTA: f64 = 2.0;
pub const LLM_EPSILON: f64 = 0.001;
pub const LLM_BASE_SETUP_GAS: f64 = 500.0;

let token_component = LLM_ALPHA * params_b * (prompt + LLM_BETA * completion);
let memory_component = LLM_GAMMA * seq_len * sqrt_b;
let linear_penalty = LLM_DELTA * delta_2k * sqrt_b;
let quadratic_penalty = LLM_EPSILON * delta_4k.powi(2) * sqrt_b;
LLM_BASE_SETUP_GAS + config.theta * (token_component + memory_component) + linear_penalty + quadratic_penalty
